app.config['MAIL_USE_TLS'] = False
app.config['MAIL_USE_SSL'] = True

db = SQLAlchemy(app)
mail = Mail(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    password_reset_token = db.Column(db.String(120))

def generate_password_reset_token(email):
    serializer = URLSafeTimedSerializer(app.config['SECRET_KEY'])
    return serializer.dumps(email, salt=app.config['SECURITY_PASSWORD_SALT'])

@app.route('/reset-password', methods=['POST'])
def reset_password():
    email = request.form['email']
    user = User.query.filter_by(email=email).first()
    if user:
        token = generate_password_reset_token(email)
        user.password_reset_token = token
        db.session.commit()

        reset_url = request.host_url + 'reset-password/token'

        msg = Message("Password Reset Request", sender='noreply@demo.com', recipients=[email])
        msg.body = f'Hello, \nPlease use this link to reset your password: {reset_url}'
        mail.send(msg)

        return 'Please check your email for a password reset link.'

    return 'User not found.'

